namespace AbpEx.Redis;public interface IRedisSortedSet : IRedisCollection{    long ZCard();    long ZCount(double min, double max);    long ZLexCount(string min, string max);    Task<long> ZCardAsync();    Task<long> ZCountAsync(double min, double max);    Task<long> ZLexCountAsync(string min, string max);}public interface IRedisSortedSet<T> : IRedisSortedSet, IRedisCollection<T> where T : notnull{    long ZAdd(Dictionary<T, double> cacheValues);    List<T> ZRange(long start, long stop);    long? ZRank(T cacheValue);    long ZRem(IList<T> cacheValues);    double? ZScore(T cacheValue);    Task<long> ZAddAsync(Dictionary<T, double> cacheValues);    Task<List<T>> ZRangeAsync(long start, long stop);    Task<long?> ZRankAsync(T cacheValue);    Task<long> ZRemAsync(IList<T> cacheValues);    Task<double?> ZScoreAsync(T cacheValue);}